PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?protectedArea ?name ?area WHERE {
  ?protectedArea wdt:P31/wdt:P279* wd:Q473972 .
  ?protectedArea wdt:P2046 ?area .
  FILTER (?area > 250000)
  OPTIONAL { ?protectedArea rdfs:label ?name . FILTER(LANG(?name) = "en") }
}
ORDER BY DESC(?area)
LIMIT 10

